        int[] y = new int[C];
        for (int i = 0; i < C; i++) {
            x[i] = scanner.nextInt();
            y[i] = scanner.nextInt();
        }
        double totalArea = 0;
        int totalSquares = 0;
        for (int i = 0; i <= N - A; i++) {
            for (int j = 0; j <= M - A; j++) {
                double squareArea = 0;
                for (int k = 0; k < C; k++) {
                    if (x[k] >= i && x[k] < i + A && y[k] >= j && y[k] < j + A) {
                        double dx = x[k] - i;
                        double dy = y[k] - j;
                        double distance = Math.sqrt(dx * dx + dy * dy);
                        if (distance <= 1) {
                            squareArea += Math.PI / 4;
                        } else if (distance <= A / 2) {
                            double angle = Math.acos(1 / distance);
                            squareArea += (angle - Math.sin(2 * angle) / 2) * 1 * 1;
                        }
                    }
                }
                totalArea += squareArea;
                totalSquares++;
            }
        }
        System.out.printf("%.6f\n", totalArea / totalSquares);
